```kotlin
import uniffi.binaryoptionstoolsuni.PocketOption
import uniffi.binaryoptionstoolsuni.Validator
import kotlinx.coroutines.runBlocking

fun main() = runBlocking {
    val api = PocketOption.init("YOUR_SESSION_ID")

    // --- send_text ---
    val handler = api.createRawHandler(Validator.new(), null)
    handler.sendText("42[\"ping\"]")

    // --- wait_next ---
    val raw = handler.waitNext()
    println("Received: $raw")

    // --- send_and_wait ---
    val balanceHandler = api.createRawHandler(
        Validator.contains("\"balance\""),
        null
    )
    val response = balanceHandler.sendAndWait("42[\"getBalance\"]")
    println("Balance response: $response")

    // --- send_binary ---
    val binaryHandler = api.createRawHandler(Validator.new(), null)
    binaryHandler.sendBinary(byteArrayOf(0x00, 0x01, 0x02).toList())

    // --- keep_alive example ---
    val subMsg = "42[\"subscribeSymbol\",\"EURUSD_otc\"]"
    val liveHandler = api.createRawHandler(
        Validator.startsWith("42[\"symbolData\"]"),
        subMsg
    )
    repeat(10) {
        val msg = liveHandler.waitNext()
        println("Symbol update: $msg")
    }
}
```

