import binaryoptionstoolsuni

func run() async throws {
    let api = try await PocketOption.init(ssid: "YOUR_SESSION_ID")

    // --- sendText ---
    let handler = try await api.createRawHandler(validator: Validator.new(), keepAlive: nil)
    try await handler.sendText(message: "42[\"ping\"]")

    // --- waitNext ---
    let raw = try await handler.waitNext()
    print("Received: \(raw)")

    // --- sendAndWait ---
    let balanceHandler = try await api.createRawHandler(
        validator: Validator.contains(substring: "\"balance\""),
        keepAlive: nil
    )
    let response = try await balanceHandler.sendAndWait(message: "42[\"getBalance\"]")
    print("Balance response: \(response)")

    // --- sendBinary ---
    let binaryHandler = try await api.createRawHandler(validator: Validator.new(), keepAlive: nil)
    try await binaryHandler.sendBinary(data: [0x00, 0x01, 0x02])

    // --- keepAlive example ---
    let subMsg = "42[\"subscribeSymbol\",\"EURUSD_otc\"]"
    let liveHandler = try await api.createRawHandler(
        validator: Validator.startsWith(prefix: "42[\"symbolData\"]"),
        keepAlive: subMsg
    )
    for _ in 0..<10 {
        let msg = try await liveHandler.waitNext()
        print("Symbol update: \(msg)")
    }
}
