## Go

```go
package main

import (
    "fmt"
    bot "github.com/ChipaDevTeam/BinaryOptionsTools-v2"
)

func main() {
    api, err := bot.PocketOptionInit("YOUR_SESSION_ID")
    if err != nil { panic(err) }

    // --- SendText ---
    handler, err := api.CreateRawHandler(bot.ValidatorNew(), nil)
    if err != nil { panic(err) }
    if err := handler.SendText("42[\"ping\"]"); err != nil { panic(err) }

    // --- WaitNext ---
    raw, err := handler.WaitNext()
    if err != nil { panic(err) }
    fmt.Printf("Received: %s\n", raw)

    // --- SendAndWait ---
    balanceHandler, err := api.CreateRawHandler(
        bot.ValidatorContains(`"balance"`),
        nil,
    )
    if err != nil { panic(err) }
    response, err := balanceHandler.SendAndWait(`42["getBalance"]`)
    if err != nil { panic(err) }
    fmt.Printf("Balance response: %s\n", response)

    // --- SendBinary ---
    binaryHandler, err := api.CreateRawHandler(bot.ValidatorNew(), nil)
    if err != nil { panic(err) }
    if err := binaryHandler.SendBinary([]byte{0x00, 0x01, 0x02}); err != nil { panic(err) }

    // --- KeepAlive example ---
    subMsg := `42["subscribeSymbol","EURUSD_otc"]`
    liveHandler, err := api.CreateRawHandler(
        bot.ValidatorStartsWith(`42["symbolData"]`),
        &subMsg,
    )
    if err != nil { panic(err) }
    for i := 0; i < 10; i++ {
        msg, err := liveHandler.WaitNext()
        if err != nil { break }
        fmt.Printf("Symbol update: %s\n", msg)
    }
}
```

